const initialHourly = {
  week1: 44,
  week2: 41,
  rate: 25,
  ytdWages: 167500,
  ssCap: 168600,
  stateRate: 0.05
};
const initialSalary = {
  annualSalary: 52e3,
  ytdWages: 167500,
  ssCap: 168600,
  stateRate: 0.05
};
